{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯的拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi de nátiě, kěyǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de5 na2tie3, ke3yi3 ma0?",
      "translation_en": "Hello, I'd like a small latte, okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "麻煩你，可以給我一個袋子嗎？",
      "pinyin": "Máfan nǐ, kěyǐ gěi wǒ yī ge dàizi ma?",
      "pinyin_numeric": "ma2fan5 ni3, ke3yi3 gei3 wo3 yi1 ge5 dai4zi5 ma0?",
      "translation_en": "Excuse me, could you give me a bag?",
      "translation_ko": "실례합니다, 봉투 하나 주실 수 있나요?"
    },
    {
      "text": "不好意思，可以幫我加珍珠嗎？",
      "pinyin": "Bù hǎo yìsi, kěyǐ bāng wǒ jiā zhēnzhū ma?",
      "pinyin_numeric": "bu4 hao3 yi4si5, ke3yi3 bang1 wo3 jia1 zhen1zhu1 ma0?",
      "translation_en": "Excuse me, could you add boba for me?",
      "translation_ko": "죄송합니다, 제게 타피오카 펄을 추가해 주실 수 있나요?"
    },
    {
      "text": "店員，可以給我半糖的紅茶嗎？",
      "pinyin": "Diànyuán, kěyǐ gěi wǒ bàn táng de hóngchá ma?",
      "pinyin_numeric": "dian4yuan2, ke3yi3 gei3 wo3 ban4 tang2 de5 hong2cha2 ma0?",
      "translation_en": "Cashier, could you give me half-sugar black tea?",
      "translation_ko": "점원님, 반당 홍차를 주실 수 있나요?"
    },
    {
      "text": "我想要一杯大杯的豆漿，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi dà bēi de dòujiāng, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 da4 bei1 de5 dou4jiang1, ke3yi3 ma0?",
      "translation_en": "I'd like a large soy milk, okay?",
      "translation_ko": "큰 컵의 두유를 원하는데 괜찮을까요?"
    },
    {
      "text": "不好意思，可以幫我外帶嗎？",
      "pinyin": "Bù hǎo yìsi, kěyǐ bāng wǒ wàidài ma?",
      "pinyin_numeric": "bu4 hao3 yi4si5, ke3yi3 bang1 wo3 wai4dai4 ma0?",
      "translation_en": "Excuse me, could you make it to-go for me?",
      "translation_ko": "죄송합니다, 포장해 주실 수 있나요?"
    },
    {
      "text": "麻煩你，可以給我一個吸管嗎？",
      "pinyin": "Máfan nǐ, kěyǐ gěi wǒ yī ge xīguǎn ma?",
      "pinyin_numeric": "ma2fan5 ni3, ke3yi3 gei3 wo3 yi1 ge5 xi1guan3 ma0?",
      "translation_en": "Excuse me, could you give me a straw?",
      "translation_ko": "실례합니다, 빨대 하나 주실 수 있나요?"
    },
    {
      "text": "店員，可以幫我少冰嗎？",
      "pinyin": "Diànyuán, kěyǐ bāng wǒ shǎo bīng ma?",
      "pinyin_numeric": "dian4yuan2, ke3yi3 bang1 wo3 shao3 bing1 ma0?",
      "translation_en": "Cashier, could you make it less ice for me?",
      "translation_ko": "점원님, 얼음 적게 해 주실 수 있나요?"
    },
    {
      "text": "我想要一杯中杯的綠茶，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi zhōng bēi de lǜchá, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 zhong1 bei1 de5 lü4cha2, ke3yi3 ma0?",
      "translation_en": "I'd like a medium green tea, okay?",
      "translation_ko": "중간 컵의 녹차를 원하는데 괜찮을까요?"
    },
    {
      "text": "不好意思，可以給我一個湯匙嗎？",
      "pinyin": "Bù hǎo yìsi, kěyǐ gěi wǒ yī ge tāngchí ma?",
      "pinyin_numeric": "bu4 hao3 yi4si5, ke3yi3 gei3 wo3 yi1 ge5 tang1chi2 ma0?",
      "translation_en": "Excuse me, could you give me a spoon?",
      "translation_ko": "죄송합니다, 숟가락 하나 주실 수 있나요?"
    }
  ]
}
